"use client";

import * as React from "react";
import * as z from "zod";
import { fieldConfig, ZodProvider } from "@acp-autoform/zod";

import { AutoForm } from "@/components/ui/autoform";
import {
  CountrySelectField,
  StateSelectField,
  CouponCodeFieldWrapper,
  GiftMessageField,
  PaymentFieldWrapper,
} from "@/components/ecommerce-checkout-fields";

const schema = z
  .object({
    country: z
      .string()
      .min(1, "Country is required")
      .describe("Country")
      .check(fieldConfig({ fieldType: "country" })),

    state: z
      .string()
      .min(1, "State / province is required")
      .describe("State / Province")
      .check(fieldConfig({ fieldType: "state" })),

    haveCoupon: z
      .boolean()
      .optional()
      .default(false)
      .describe("Have a coupon?"),

    couponCode: z
      .string()
      .optional()
      .describe("Coupon code")
      .check(
        fieldConfig({
          fieldWrapper: CouponCodeFieldWrapper,
          inputProps: { placeholder: "Try free100" },
        }),
      ),

    isGift: z.boolean().optional().default(false).describe("This is a gift"),

    giftMessage: z
      .string()
      .optional()
      .describe("Gift message")
      .check(fieldConfig({ fieldType: "giftMessage" })),

    payment: z
      .object({
        cardNumber: z
          .string()
          .optional()
          .describe("Card number")
          .check(
            fieldConfig({ inputProps: { placeholder: "1234 5678 9012 3456" } }),
          ),

        expiryDate: z
          .string()
          .optional()
          .describe("Expiry (MM/YY)")
          .check(fieldConfig({ inputProps: { placeholder: "MM/YY" } })),

        cvv: z
          .string()
          .min(3)
          .max(4)
          .optional()
          .describe("CVV")
          .check(fieldConfig({ inputProps: { placeholder: "123" } })),
      })
      .check(fieldConfig({ fieldWrapper: PaymentFieldWrapper })), // for a discount banner when FREE100 is active.
  })
  .superRefine((data, ctx) => {
    if (data.haveCoupon && !data.couponCode?.trim()) {
      ctx.addIssue({
        code: "custom",
        message: "Coupon code is required",
        path: ["couponCode"],
      });
    }

    const isFree =
      data.haveCoupon && data.couponCode?.toUpperCase() === "FREE100";

    if (!isFree) {
      if (!data.payment?.cardNumber?.trim())
        ctx.addIssue({
          code: "custom",
          message: "Card number is required",
          path: ["payment", "cardNumber"],
        });
      if (!data.payment?.expiryDate?.trim())
        ctx.addIssue({
          code: "custom",
          message: "Expiry date is required",
          path: ["payment", "expiryDate"],
        });
      if (!data.payment?.cvv?.trim())
        ctx.addIssue({
          code: "custom",
          message: "CVV is required",
          path: ["payment", "cvv"],
        });
    }
  });

type CheckoutValues = z.infer<typeof schema>;

const schemaProvider = new ZodProvider(schema);

export function EcommerceCheckoutDemo() {
  const [result, setResult] = React.useState<CheckoutValues | null>(null);

  return (
    <div className="rounded-lg border bg-background p-6 space-y-6">
      <AutoForm
        schema={schemaProvider}
        formComponents={{
          country: CountrySelectField,
          state: StateSelectField,
          giftMessage: GiftMessageField,
        }}
        onSubmit={(data) => setResult(data as CheckoutValues)}
        withSubmit
      />

      {result && (
        <div className="rounded-md border bg-secondary/50 p-4 text-sm">
          <div className="font-medium mb-2">Submitted value</div>
          <pre className="overflow-auto text-xs">
            {JSON.stringify(result, null, 2)}
          </pre>
        </div>
      )}
    </div>
  );
}

"use client";
import { useController } from "react-hook-form";

import * as React from "react";
import { useFormContext, useWatch } from "react-hook-form";
import type {
  AutoFormFieldProps,
  FieldWrapperProps,
} from "@acp-autoform/react";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

// ── Data ──────────────────────────────────────────────────────────────────────

interface CountryEntry {
  name: string;
  iso2: string;
  states: { name: string; state_code: string }[];
}

let _countriesPromise: Promise<CountryEntry[]> | null = null;
const fetchCountries = () =>
  (_countriesPromise ??= fetch(
    "https://countriesnow.space/api/v0.1/countries/states",
  )
    .then((r) => r.json())
    .then((j) => (j.data as CountryEntry[]) ?? [])
    .catch(() => []));

function useCountries() {
  const [countries, setCountries] = React.useState<CountryEntry[]>([]);
  React.useEffect(() => {
    fetchCountries().then(setCountries);
  }, []);

  const labels = React.useMemo(() => {
    const counts = new Map<string, number>();
    countries.forEach((c) => counts.set(c.name, (counts.get(c.name) ?? 0) + 1));
    return new Map(
      // Countries sharing a name (e.g. the two "Congo" entries) get iso2 appended
      countries.map((c) => [
        c.iso2,
        counts.get(c.name)! > 1 ? `${c.name} (${c.iso2})` : c.name,
      ]),
    );
  }, [countries]);

  return { countries, labels };
}

// ── CountrySelectField ────────────────────────────────────────────────────────
export function CountrySelectField({ id, error }: AutoFormFieldProps) {
  const { field } = useController({ name: id });
  const { setValue } = useFormContext();
  const { countries, labels } = useCountries();

  return (
    <Select
      onValueChange={(iso2: string) => {
        field.onChange(iso2);
        setValue("state", "");
      }}
      value={field.value ?? ""}
      disabled={countries.length === 0}
    >
      <SelectTrigger
        id={id}
        ref={field.ref}
        className={error ? "border-destructive" : ""}
      >
        <SelectValue
          placeholder={
            countries.length === 0 ? "Loading countries…" : "Select a country"
          }
        />
      </SelectTrigger>
      <SelectContent>
        {countries.map((c) => (
          <SelectItem key={c.iso2} value={c.iso2}>
            {labels.get(c.iso2) ?? c.name}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  );
}

// ── StateSelectField ──────────────────────────────────────────────────────────
export function StateSelectField({ id, error }: AutoFormFieldProps) {
  const { field } = useController({ name: id });
  const { countries } = useCountries();
  const selectedIso2: string = useWatch({ name: "country" });

  const states = React.useMemo(
    () => countries.find((c) => c.iso2 === selectedIso2)?.states ?? [],
    [countries, selectedIso2],
  );

  const placeholder = !selectedIso2
    ? "Select a country first"
    : states.length === 0
      ? "No states available"
      : "Select a state / province";

  return (
    <Select
      onValueChange={field.onChange}
      value={field.value ?? ""}
      disabled={!selectedIso2 || states.length === 0}
    >
      <SelectTrigger
        id={id}
        ref={field.ref}
        className={error ? "border-destructive" : ""}
      >
        <SelectValue placeholder={placeholder} />
      </SelectTrigger>
      <SelectContent>
        {states.map((s) => (
          <SelectItem key={s.state_code} value={s.name}>
            {s.name}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  );
}

// ── CouponCodeFieldWrapper ──────────────────────────────────────────────────
// Returns null (field hidden entirely) when "Have a coupon?" is unchecked.
export function CouponCodeFieldWrapper({
  children,
  label,
  id,
  error,
  parsedField,
}: FieldWrapperProps) {
  const haveCoupon = useWatch({ name: "haveCoupon" });

  if (!haveCoupon) return null;

  return (
    <div className="flex flex-col gap-2">
      <Label htmlFor={id}>
        {label}
        {parsedField.required && <span className="text-destructive"> *</span>}
      </Label>
      {children}
      {error && <div className="text-sm text-destructive">{error}</div>}
    </div>
  );
}

// ── GiftMessageField ──────────────────────────────────────────────────────────
// Always visible; editable only when "This is a gift" is checked.
export function GiftMessageField({
  id,
  error,
  inputProps,
  parsedField,
}: AutoFormFieldProps) {
  const { field } = useController({ name: id });
  const isGift = useWatch({ name: "isGift" });

  return (
    <Textarea
      id={id}
      placeholder="Write a gift message…"
      rows={3}
      disabled={!isGift}
      className={error ? "border-destructive" : ""}
      {...inputProps}
      {...field}
      value={field.value ?? ""}
    />
  );
}

// ── PaymentFieldWrapper ───────────────────────────────────────────────────────
// Wraps the entire payment section: renders children normally, or swaps
// them for a discount banner when the FREE100 coupon is active.
export function PaymentFieldWrapper({ children }: FieldWrapperProps) {
  const { subscribe } = useFormContext();
  const [isFree, setIsFree] = React.useState(false);

  React.useEffect(() => {
    // see react-hook-form docs for subscribe: https://react-hook-form.com/docs/useform/subscribe
    const callback = subscribe({
      name: ["couponCode", "haveCoupon"],
      formState: {
        values: true,
      },
      callback: ({ values }) => {
        const isFreeNow =
          values.haveCoupon && values.couponCode?.toUpperCase() === "FREE100";
        setIsFree(isFreeNow);
      },
    });
    return () => callback();
  }, [subscribe]);

  if (isFree) {
    return (
      <div className="rounded-lg border border-green-500/40 bg-green-500/10 p-4 text-sm text-green-700 dark:text-green-400">
        🎉 100% discount applied, no payment required!
      </div>
    );
  }

  return <>{children}</>;
}
